import time
import json
from datetime import datetime


class Logger:
    def __init__(self):
        self.start_time = None
        self.trace = {}

    def start(self):
        self.start_time = time.time()
        self.trace["start_time"] = datetime.utcnow().isoformat()

    def log(self, key, value):
        self.trace[key] = value

    def end(self):
        self.trace["latency_ms"] = round((time.time() - self.start_time) * 1000, 2)
        self.trace["end_time"] = datetime.utcnow().isoformat()
        return self.trace

    def print(self):
        # default=str avoids runtime failures for uncommon non-JSON-native objects.
        print(json.dumps(self.trace, indent=2, default=str))

import json
import time
from datetime import datetime


class Logger:
    def __init__(self):
        self.start_time = None
        self.trace = {}

    def start(self):
        self.start_time = time.time()
        self.trace["start_time"] = datetime.utcnow().isoformat()

    def log(self, key, value):
        self.trace[key] = value

    def end(self):
        self.trace["latency_ms"] = round((time.time() - self.start_time) * 1000, 2)
        self.trace["end_time"] = datetime.utcnow().isoformat()
        return self.trace

    def print(self):
        print(json.dumps(self.trace, indent=2, default=str))

from app.core.config import HIGH_CONFIDENCE, RAG_CONFIG
from app.orchestration.prefilter import compute_intent_scores


def get_dynamic_k(top1, top2):
    gap = top1 - top2 if top2 is not None else 1.0
    if gap >= RAG_CONFIG["high_gap"]:
        return RAG_CONFIG["k_small"]
    if gap >= RAG_CONFIG["low_gap"]:
        return RAG_CONFIG["k_medium"]
    return RAG_CONFIG["k_large"]


def is_rag_reliable(top1_score):
    return top1_score >= RAG_CONFIG["min_top1_score"]


def choose_route(query: str):
    scores = compute_intent_scores(query)
    best_route = max(scores, key=scores.get)
    best_score = float(scores[best_route])

    debug = {
        "query": query,
        "intent_scores": {k: float(v) for k, v in scores.items()},
        "best_route": best_route,
        "best_score": best_score,
        "high_confidence_threshold": float(HIGH_CONFIDENCE),
    }

    return best_route, best_score, debug

from app.orchestration.decision_engine import get_dynamic_k, is_rag_reliable from app.retrieval.rag import retrieve
def handle_rag_route(query: str, debug: dict): debug["entered_branch"] = "rag_candidate" chunks = retrieve(query) debug["retrieved_chunk_count"] = len(chunks)
if not chunks: debug["decision"] = "direct_no_rag_chunks" return { "route": "direct", "query": query, "context": None, "debug": debug, }
top1 = chunks[0]["score"] top2 = chunks[1]["score"] if len(chunks) > 1 else None debug["rag_top1"] = float(top1) debug["rag_top2"] = float(top2) if top2 is not None else None
if not is_rag_reliable(top1): debug["decision"] = "direct_low_rag_confidence" return { "route": "direct", "query": query, "context": None, "debug": debug, }
k = get_dynamic_k(top1, top2) debug["rag_dynamic_k"] = int(k) debug["decision"] = "rag"
return { "route": "rag", "query": query, "context": chunks[:k], "debug": debug, }

from app.core.config import HIGH_CONFIDENCE
from app.services.tools.stock_price_tool import get_stock_price
from app.services.tools.ticker_extractor import extract_ticker


def handle_tool_route(query: str, best_score: float, debug: dict):
    debug["entered_branch"] = "tool"

    if best_score < HIGH_CONFIDENCE:
        debug["decision"] = "clarify_low_tool_confidence"
        return {
            "route": "clarify",
            "message": "Could you specify the stock symbol or company name?",
            "debug": debug,
        }

    ticker = extract_ticker(query)
    debug["extracted_ticker"] = ticker

    if not ticker:
        debug["decision"] = "clarify_ticker_not_found"
        return {
            "route": "clarify",
            "message": "Could you specify the stock symbol (e.g. AAPL)?",
            "debug": debug,
        }

    tool_result = get_stock_price(ticker)
    debug["tool_result_preview"] = {
        "ticker": tool_result.get("ticker"),
        "price": tool_result.get("price"),
        "change_percent": tool_result.get("change_percent"),
    }
    debug["decision"] = "tool"

    return {
        "route": "tool",
        "query": query,
        "context": tool_result,
        "debug": debug,
    }

from app.orchestration.prefilter import compute_intent_scores
from app.retrieval.rag import retrieve
from app.services.tools_services import get_stock_price, extract_ticker
from app.core.config import RAG_CONFIG, HIGH_CONFIDENCE


def get_dynamic_k(top1, top2):
    gap = top1 - top2 if top2 is not None else 1.0
    if gap >= RAG_CONFIG["high_gap"]:
        return RAG_CONFIG["k_small"]
    if gap >= RAG_CONFIG["low_gap"]:
        return RAG_CONFIG["k_medium"]
    return RAG_CONFIG["k_large"]


def is_rag_reliable(top1_score):
    return top1_score >= RAG_CONFIG["min_top1_score"]


def route_query(query: str):
    scores = compute_intent_scores(query)
    best_route = max(scores, key=scores.get)
    best_score = scores[best_route]

    debug = {
        "query": query,
        "intent_scores": {k: float(v) for k, v in scores.items()},
        "best_route": best_route,
        "best_score": float(best_score),
        "high_confidence_threshold": float(HIGH_CONFIDENCE),
    }

    if best_route == "tool":
        debug["entered_branch"] = "tool"

        if best_score < HIGH_CONFIDENCE:
            debug["decision"] = "clarify_low_tool_confidence"
            return {
                "route": "clarify",
                "message": "Could you specify the stock symbol or company name?",
                "debug": debug,
            }

        ticker = extract_ticker(query)
        debug["extracted_ticker"] = ticker

        if not ticker:
            debug["decision"] = "clarify_ticker_not_found"
            return {
                "route": "clarify",
                "message": "Could you specify the stock symbol (e.g. AAPL)?",
                "debug": debug,
            }

        tool_result = get_stock_price(ticker)
        debug["tool_result_preview"] = {
            "ticker": tool_result.get("ticker"),
            "price": tool_result.get("price"),
            "change_percent": tool_result.get("change_percent"),
        }
        debug["decision"] = "tool"

        return {
            "route": "tool",
            "query": query,
            "context": tool_result,
            "debug": debug,
        }

    if best_route == "direct":
        debug["entered_branch"] = "direct"
        debug["decision"] = "direct_by_intent"
        return {
            "route": "direct",
            "query": query,
            "context": None,
            "debug": debug,
        }

    debug["entered_branch"] = "rag_candidate"
    chunks = retrieve(query)
    debug["retrieved_chunk_count"] = len(chunks)

    if not chunks:
        debug["decision"] = "direct_no_rag_chunks"
        return {
            "route": "direct",
            "query": query,
            "context": None,
            "debug": debug,
        }

    top1 = chunks[0]["score"]
    top2 = chunks[1]["score"] if len(chunks) > 1 else None
    debug["rag_top1"] = float(top1)
    debug["rag_top2"] = float(top2) if top2 is not None else None

    if not is_rag_reliable(top1):
        debug["decision"] = "direct_low_rag_confidence"
        return {
            "route": "direct",
            "query": query,
            "context": None,
            "debug": debug,
        }

    k = get_dynamic_k(top1, top2)

    for chunk in chunks[:k]:
        print(chunk["chunk"])
        print("=" * 50)

    debug["rag_dynamic_k"] = int(k)
    debug["decision"] = "rag"

    return {
        "route": "rag",
        "query": query,
        "context": chunks[:k],
        "debug": debug,
    }

from app.orchestration.decision_engine import choose_route
from app.orchestration.handlers.rag_handler import handle_rag_route
from app.orchestration.handlers.tool_handler import handle_tool_route
from app.orchestration.state import RoutedQuery


def route_query(query: str) -> RoutedQuery:
    best_route, best_score, debug = choose_route(query)

    if best_route == "tool":
        return handle_tool_route(query=query, best_score=best_score, debug=debug)

    if best_route == "direct":
        debug["entered_branch"] = "direct"
        debug["decision"] = "direct_by_intent"
        return {
            "route": "direct",
            "query": query,
            "context": None,
            "debug": debug,
        }

    return handle_rag_route(query=query, debug=debug)

import ollama
def generate_response(messages: list): response = ollama.chat( model="llama3:latest", messages=messages )
return response["message"]["content"]

import os

import requests
from dotenv import load_dotenv

load_dotenv()

FINNHUB_API_KEY = os.getenv("FINNHUB_API_KEY")
BASE_URL = "https://finnhub.io/api/v1"


def search_symbol(keywords: str):
    if not FINNHUB_API_KEY:
        return None

    try:
        response = requests.get(
            f"{BASE_URL}/search",
            params={"q": keywords, "token": FINNHUB_API_KEY},
            timeout=10,
        )
        response.raise_for_status()
        data = response.json()
    except requests.RequestException:
        return None

    results = data.get("result", [])
    if not results:
        return None

    for item in results:
        if item.get("type") == "Common Stock":
            return item.get("symbol", "").upper()

    return results[0].get("symbol", "").upper() or None


def quote_symbol(ticker: str):
    try:
        response = requests.get(
            f"{BASE_URL}/quote",
            params={"symbol": ticker, "token": FINNHUB_API_KEY},
            timeout=10,
        )
        response.raise_for_status()
        return response.json()
    except requests.RequestException:
        return None

from app.services.tools.finnhub_client import quote_symbol
def get_stock_price(ticker: str): quote = quote_symbol(ticker) if quote is None: return { "tool": "stock_price", "ticker": ticker, "price": 0, "change": 0, "change_percent": "0%", "raw_timestamp": None, }
current_price = quote.get("c", 0) prev_close = quote.get("pc", 0) change = quote.get("d", 0) change_pct = quote.get("dp", 0)
return { "tool": "stock_price", "ticker": ticker, "price": float(current_price or 0), "change": float(change or 0), "change_percent": f"{float(change_pct or 0):.2f}%", "raw_timestamp": prev_close, }

import re

from app.services.tools.finnhub_client import search_symbol


def extract_ticker(query: str):
    explicit = re.search(
        r"(?:ticker|symbol)\s*(?:is|=|:)?\s*\$?([A-Za-z]{1,6}(?:\.[A-Za-z]{1,2})?)",
        query,
        flags=re.IGNORECASE,
    )
    if explicit:
        return explicit.group(1).upper()

    dollar = re.search(r"\$([A-Za-z]{1,6}(?:\.[A-Za-z]{1,2})?)", query)
    if dollar:
        return dollar.group(1).upper()

    upper_token = re.search(r"\b([A-Z]{1,6}(?:\.[A-Z]{1,2})?)\b", query)
    if upper_token:
        return upper_token.group(1).upper()

    return search_symbol(query)

import requests
import os
import re
from dotenv import load_dotenv

load_dotenv()

FINNHUB_API_KEY = os.getenv("FINNHUB_API_KEY")
BASE_URL = "https://finnhub.io/api/v1"


def _search_symbol(keywords: str):
    """Resolve symbol dynamically via Finnhub symbol search."""
    if not FINNHUB_API_KEY:
        return None

    try:
        response = requests.get(
            f"{BASE_URL}/search",
            params={"q": keywords, "token": FINNHUB_API_KEY},
            timeout=10
        )
        response.raise_for_status()
        data = response.json()
    except requests.RequestException:
        return None

    results = data.get("result", [])
    if not results:
        return None

    # Return first common stock match
    for item in results:
        if item.get("type") == "Common Stock":
            return item.get("symbol", "").upper()

    # Fallback to first result
    return results[0].get("symbol", "").upper() or None


def extract_ticker(query: str):
    # 1) Explicit forms: "ticker TSLA", "symbol: nvda"
    explicit = re.search(
        r"(?:ticker|symbol)\s*(?:is|=|:)?\s*\$?([A-Za-z]{1,6}(?:\.[A-Za-z]{1,2})?)",
        query,
        flags=re.IGNORECASE,
    )
    if explicit:
        return explicit.group(1).upper()

    # 2) Dollar-prefixed form: "$aapl"
    dollar = re.search(r"\$([A-Za-z]{1,6}(?:\.[A-Za-z]{1,2})?)", query)
    if dollar:
        return dollar.group(1).upper()

    # 3) Already uppercase ticker in text
    upper_token = re.search(r"\b([A-Z]{1,6}(?:\.[A-Z]{1,2})?)\b", query)
    if upper_token:
        return upper_token.group(1).upper()

    # 4) Dynamic fallback for lowercase tickers or company names
    return _search_symbol(query)


def get_stock_price(ticker: str):
    try:
        response = requests.get(
            f"{BASE_URL}/quote",
            params={"symbol": ticker, "token": FINNHUB_API_KEY},
            timeout=10
        )
        response.raise_for_status()
        quote = response.json()
    except requests.RequestException:
        return {
            "tool": "stock_price",
            "ticker": ticker,
            "price": 0,
            "change": 0,
            "change_percent": "0%",
            "raw_timestamp": None
        }

    current_price = quote.get("c", 0)   # current price
    prev_close    = quote.get("pc", 0)  # previous close
    change        = quote.get("d", 0)   # change
    change_pct    = quote.get("dp", 0)  # change percent

    return {
        "tool": "stock_price",
        "ticker": ticker,
        "price": float(current_price or 0),
        "change": float(change or 0),
        "change_percent": f"{float(change_pct or 0):.2f}%",
        "raw_timestamp": prev_close   # Finnhub doesn't return trading day, use prev close instead
    }
